from flask import Flask, session, request, redirect, url_for, flash
import hashlib

app = Flask(__name__)
app.secret_key = 'your-secret-key'  # Change this to a secure secret key

# Initialize the session extension
app.config['SESSION_TYPE'] = 'filesystem'

SESS_COOKIE_NAME = 'session'

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def check_password(stored_hash, input_password):
    return stored_hash == hash_password(input_password)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        password = request.form['password']
        if check_password('stored-hashed-password', password):  # Replace with your stored hashed password
            session[SESS_COOKIE_NAME] = 'logged_in'
            return redirect(url_for('home'))
        else:
            flash('Invalid password')
    return '''
        <form method="post">
            Password:<br>
            <input type="password" name="password"><br>
            <input type="submit" value="Submit">
        </form>
    '''

@app.route('/logout')
def logout():
    session.pop(SESS_COOKIE_NAME, None)
    return redirect(url_for('login'))

@app.route('/home')
def home():
    if not session.get(SESS_COOKIE_NAME):
        return redirect(url_for('login'))
    return 'Welcome to the home page!'

if __name__ == '__main__':
    app.run()